parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const repo = body.repository || {};
const cloneUrl = repo.clone_url || '';
const ref = body.ref || 'refs/heads/main';
const branch = ref.replace(/^refs\/heads\//, '');
const fullName = repo.full_name || repo.name || 'unknown';
const commitSha = body.after || '';
const pusher = body.pusher || {};
const pusherEmail = pusher.email || (body.sender && body.sender.email) || 'noreply@local';
const token = typeof process !== 'undefined' && process.env && process.env.GITEA_API_TOKEN;
let authCloneUrl = cloneUrl;
if (token && cloneUrl && cloneUrl.startsWith('http')) {
  try {
    const u = new URL(cloneUrl);
    u.username = token;
    u.password = '';
    authCloneUrl = u.toString().replace(/:\/\//, '://' + token + '@');
  } catch (_) { authCloneUrl = cloneUrl; }
}
return [{ json: {
  clone_url: cloneUrl,
  auth_clone_url: authCloneUrl,
  full_name: fullName,
  branch,
  commit_sha: commitSha,
  pusher_email: pusherEmail,
  ref
} }];

const cmdOut = $input.first().json;
const stdout = cmdOut.stdout || '';
const parsePayload = $('Parse Gitea Payload').first().json;
let hasCritical = false;
let criticalVulns = [];
try {
  const trivy = stdout ? JSON.parse(stdout) : { Results: [] };
  const results = trivy.Results || [];
  for (const r of results) {
    const vulns = r.Vulnerabilities || [];
    for (const v of vulns) {
      if (v.Severity === 'CRITICAL') {
        hasCritical = true;
        criticalVulns.push({
          VulnerabilityID: v.VulnerabilityID || v.VulnerabilityId,
          PkgName: v.PkgName,
          Title: v.Title || '',
          Severity: v.Severity
        });
      }
    }
  }
} catch (_) {}
return [{ json: {
  has_critical: hasCritical,
  critical_vulns: criticalVulns,
  full_name: parsePayload.full_name,
  branch: parsePayload.branch,
  commit_sha: parsePayload.commit_sha,
  pusher_email: parsePayload.pusher_email
} }];

parameters.jsonBody:
={{ JSON.stringify({
  title: 'CRITICAL vulnerabilities: ' + $json.full_name + ' (' + $json.branch + ')',
  group: 'Users',
  customer: $json.pusher_email,
  article: {
    subject: 'SBOM/Trivy scan found CRITICAL vulns in ' + $json.full_name,
    body: 'Repository: ' + $json.full_name + '\nBranch: ' + $json.branch + '\nCommit: ' + $json.commit_sha + '\nPusher: ' + $json.pusher_email + '\n\nCritical vulnerabilities:\n' + (($json.critical_vulns || []).map(function(v) { return '- ' + (v.VulnerabilityID || '') + ' ' + (v.PkgName || '') + ' ' + (v.Title || ''); }).join('\n'))
  }
}) }}

parameters.responseBody:
={{ JSON.stringify({
  scan_result: 'critical',
  message: 'Zammad ticket created for critical vulnerabilities.',
  ticket_id: $json.id,
  ticket_url: ($env.ZAMMAD_URL || 'http://zammad') + '/#ticket/zoom/' + $json.id
}) }}
